// แปลงผลดิบ Shopee → schema ของ backend (ปรับ field ตามจริง)
const raw = $input.first().json;
const items = (raw.items || raw.data?.items || []);
const stores = items.map(it => {
  const b = it.item_basic || it;
  return {
    name: b.name || b.shop_name || 'ร้านไม่ทราบชื่อ',
    area: 'อุดรธานี',
    rating: Number((b.item_rating?.rating_star ?? b.rating ?? 0).toFixed(1)),
    review_count: b.item_rating?.rating_count?.[0] ?? b.review_count ?? 0,
    price_range: b.price ? `~${Math.round(b.price/100000)} บาท` : '',
    menu: (b.name || '').split(' ').slice(0,4),
    image_urls: b.image ? [`https://cf.shopee.co.th/file/${b.image}`] : [],
    shopee_url: b.shopid ? `https://shopee.co.th/product/${b.shopid}/${b.itemid}` : '',
    affiliate_link: ''
  };
});
return [{ json: { stores } }];
